const claudeResp = $('Expand Prompt with Claude').item.json;
const input = $('Generate Video Webhook').item.json;
const text = claudeResp.content[0].text;
let prompts;
try { prompts = JSON.parse(text.replace(/```json|```/g,'')); } 
catch(e) { prompts = {positive_prompt: text, negative_prompt: 'blurry, watermark, low quality, deformed'}; }

const w = input.resolution === '720p' ? 1280 : 832;
const h = input.resolution === '720p' ? 720 : 480;
const frames = Math.min(Math.max(Math.floor((input.duration_seconds || 5) * 16), 17), 97);

return {
  positive_prompt: prompts.positive_prompt,
  negative_prompt: prompts.negative_prompt || 'blurry, watermark, distorted, low quality',
  width: w,
  height: h,
  num_frames: frames,
  steps: 20,
  cfg_scale: 7.5,
  project: input.project || 'default',
  original_brief: input.prompt
};

const history = $input.item.json;
const promptId = $('Submit to ComfyUI').item.json.prompt_id;
const job = history[promptId];
if (!job || !job.outputs) return [{done: false}];
const outputs = Object.values(job.outputs);
const videoNode = outputs.find(o => o.gifs || o.videos);
if (!videoNode) return [{done: false}];
const files = videoNode.gifs || videoNode.videos || [];
if (files.length === 0) return [{done: false}];
return [{done: true, filename: files[0].filename, subfolder: files[0].subfolder || ''}];
